+func TestExtractJSONOutputs(t *testing.T) {
+	t.Parallel()
+
+	tests := []struct {
+		name    string
+		content string
+		want    int // number of JSON outputs
+		isArray []bool
+	}{
+		{
+			name:    "empty content",
+			content: "",
+			want:    0,
+		},
+		{
+			name:    "no JSON",
+			content: "Just some text",
+			want:    0,
+		},
+		{
+			name:    "simple object",
+			content: `{"key": "value"}`,
+			want:    1,
+			isArray: []bool{false},
+		},
+		{
+			name:    "simple array",
+			content: `[1, 2, 3]`,
+			want:    1,
+			isArray: []bool{true},
+		},
+		{
+			name:    "multiline object",
+			content: "{\n  \"key\": \"value\",\n  \"num\": 42\n}",
+			want:    1,
+			isArray: []bool{false},
+		},
+		{
+			name:    "object with nested",
+			content: `{"outer": {"inner": true}}`,
+			want:    1,
+			isArray: []bool{false},
+		},
+		{
+			name:    "invalid JSON",
+			content: `{"key": value}`,
+			want:    0,
+		},
+		{
+			name:    "mixed content",
+			content: "Output:\n{\"success\": true}\nDone",
+			want:    1,
+			isArray: []bool{false},
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			t.Parallel()
+			got := ExtractJSONOutputs(tt.content)
+			if len(got) != tt.want {
+				t.Fatalf("got %d JSON outputs, want %d", len(got), tt.want)
+			}
+			for i, g := range got {
+				if i < len(tt.isArray) && g.IsArray != tt.isArray[i] {
+					t.Errorf("output[%d].IsArray = %v, want %v", i, g.IsArray, tt.isArray[i])
+				}
+			}
+		})
+	}
+}
