+func TestIsValidJSON(t *testing.T) {
+	t.Parallel()
+
+	tests := []struct {
+		input string
+		want  bool
+	}{
+		{`{}`, true},
+		{`[]`, true},
+		{`{"key": "value"}`, true},
+		{`[1, 2, 3]`, true},
+		{`{"nested": {"deep": true}}`, true},
+		{``, false},
+		{`{invalid}`, false},
+		{`{"key": }`, false},
+		{`just text`, false},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.input, func(t *testing.T) {
+			t.Parallel()
+			if got := isValidJSON(tt.input); got != tt.want {
+				t.Errorf("isValidJSON(%q) = %v, want %v", tt.input, got, tt.want)
+			}
+		})
+	}
+}
