+func TestOutputCapture_Stats(t *testing.T) {
+	t.Parallel()
+
+	oc := NewOutputCapture(nil)
+	oc.CaptureAndExtract("%1", "claude", "content", "")
+	oc.CaptureAndExtract("%1", "claude", "content", "")
+	oc.CaptureAndExtract("%2", "codex", "content", "")
